def enumerate_items(items, item_formatter=None):
    if item_formatter is not None:
        items = [item_formatter(item) for item in items]
    if not items:
        return ""
    *rest, last = items
    if not rest:
        return last

    last_joiner = ", and " if len(rest) > 1 else " and "  # Oxford comma
    return last_joiner.join((", ".join(rest), last))

def tag_hint(request):
    q = request.GET.get("q", "")
    results = []
    if len(q) > MIN_QUERY_LENGTH:
        tag_qs = Tag.objects.filter(slug__startswith=q)
        annotated_qs = tag_qs.annotate(count=Count("taggit_taggeditem_items__id"))

        results = [
            {"tag": obj.slug, "count": obj.count}
            for obj in annotated_qs.order_by("-count", "slug")[:10]
        ]

    return HttpResponse(json.dumps(results), content_type="application/json")

